                  <Block className={"div-block-1896"} tag={"div"}>
                    <Copy
                      text={
                        "In 2025, Toronto welcomes the first-ever Meet Magento Canada, proudly hosted by scandiweb. This landmark event connects Magento specialists, Adobe Commerce professionals, merchants, and developers from across Canada and internationally. Participants engage in insightful discussions on emerging eCommerce strategies, innovative platform solutions, and actionable paths to growth, while actively networking to build the Magento community in Canada."
                      }
                      variant={"Inter/400/16/28/grey"}
                    />
                  </Block>
